import { describe, expect, test } from '@a0n/gnosis/test';
import { resolve } from 'node:path';

import { runGGTestFile } from './gg-test-runner';

const EXAMPLES_DIR = resolve(__dirname, '../examples');

describe('Aeon Flux site proof topology', () => {
  test('proofs/AeonFluxSiteAdequacy.test.gg passes', async () => {
    const result = await runGGTestFile(
      resolve(EXAMPLES_DIR, 'proofs/AeonFluxSiteAdequacy.test.gg')
    );

    expect(result.ok).toBe(true);
    expect(result.modules).toHaveLength(1);
    expect(result.modules[0]?.ok).toBe(true);
    expect(result.composition.ok).toBe(true);
  });
});
